import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [user, setUser] = useState(null);
  const [view, setView] = useState("dashboard");
  const [students, setStudents] = useState([]);
  const [id, setId] = useState("");
  const [pass, setPass] = useState("");

  useEffect(() => {
    if (user?.role === 'admin') {
      axios.get('http://localhost:3000/api/admin/students').then(res => setStudents(res.data));
    }
  }, [user]);

  const updateData = (sid, data) => {
    axios.put(`http://localhost:3000/api/admin/update/${encodeURIComponent(sid)}`, data);
  };

  if (!user) {
    return (
      <div style={st.loginBg}>
        <div style={st.loginCard}>
          <h2>UOB PORTAL 2026</h2>
          <input placeholder="ID" onChange={e => setId(e.target.value)} style={st.in} />
          <input type="password" placeholder="Password" onChange={e => setPass(e.target.value)} style={st.in} />
          <button onClick={() => {
            axios.post('http://localhost:3000/api/login', { id, password: pass })
              .then(res => setUser(res.data)).catch(() => alert("Khalad baa jira!"));
          }} style={st.btn}>LOGIN</button>
        </div>
      </div>
    );
  }

  return (
    <div style={{ display: 'flex', height: '100vh' }}>
      {/* SIDEBAR */}
      <div style={st.sidebar}>
        <h3>UOB PORTAL</h3>
        <button onClick={() => setView("dashboard")} style={st.mBtn}>Dashboard</button>
        {user.role === 'admin' && <button onClick={() => setView("edit")} style={st.mBtn}>Maamul Ardayda</button>}
        <button onClick={() => setUser(null)} style={st.outBtn}>Logout</button>
      </div>

      {/* CONTENT */}
      <div style={{ flex: 1, padding: '30px', background: '#f8f9fa' }}>
        {user.role === 'admin' ? (
          <table border="1" width="100%" style={{background: 'white'}}>
            <thead>
              <tr><th>ID</th><th>Magaca</th><th>Bil 1 | Mid | Bil 3 | Final</th></tr>
            </thead>
            <tbody>
              {students.slice(0, 10).map(s => (
                <tr key={s.id}>
                  <td>{s.id}</td><td>{s.magaca}</td>
                  <td>
                    <input type="number" onBlur={e => updateData(s.id, {imtixaan: {...s.imtixaan, bil1: e.target.value}})} defaultValue={s.imtixaan?.bil1} style={{width: '40px'}} />
                    <input type="number" onBlur={e => updateData(s.id, {imtixaan: {...s.imtixaan, midterm: e.target.value}})} defaultValue={s.imtixaan?.midterm} style={{width: '40px'}} />
                    <input type="number" onBlur={e => updateData(s.id, {imtixaan: {...s.imtixaan, bil3: e.target.value}})} defaultValue={s.imtixaan?.bil3} style={{width: '40px'}} />
                    <input type="number" onBlur={e => updateData(s.id, {imtixaan: {...s.imtixaan, final: e.target.value}})} defaultValue={s.imtixaan?.final} style={{width: '40px'}} />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <div style={st.card}>
            <h2>Natiijada: {user.id}</h2>
            <div style={st.grid}>
              <div style={st.box}><h4>Bil 1</h4><p>{user.imtixaan?.bil1 ?? 0}%</p></div>
              <div style={st.box}><h4>Mid-Term</h4><p>{user.imtixaan?.midterm ?? 0}%</p></div>
              <div style={st.box}><h4>Bil 3</h4><p>{user.imtixaan?.bil3 ?? 0}%</p></div>
              <div style={st.box}><h4>Final</h4><p>{user.imtixaan?.final ?? 0}%</p></div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

const st = {
  loginBg: { height: '100vh', display: 'flex', justifyContent: 'center', alignItems: 'center', background: '#eee' },
  loginCard: { background: 'white', padding: '40px', borderRadius: '10px', textAlign: 'center' },
  in: { display: 'block', margin: '10px auto', padding: '10px', width: '250px' },
  btn: { padding: '10px 40px', background: '#1a73e8', color: 'white', border: 'none', cursor: 'pointer' },
  sidebar: { width: '240px', background: '#2c3e50', color: 'white', padding: '20px' },
  mBtn: { width: '100%', padding: '15px', margin: '5px 0', textAlign: 'left', cursor: 'pointer' },
  outBtn: { background: 'red', color: 'white', width: '100%', padding: '10px', marginTop: '20px' },
  card: { background: 'white', padding: '30px', borderRadius: '15px', textAlign: 'center' },
  grid: { display: 'flex', gap: '10px', justifyContent: 'center', marginTop: '20px' },
  box: { padding: '20px', background: '#f1f1f1', borderBottom: '4px solid blue' }
};

export default App;
